  "title": "Important Facts about Sex Education",
  "lessonText": "Understanding key facts about sex education is essential for informed decision-making.",
  "data": {
    "learningCards": [
      {
        "title": "Consent",
        "content": "Consent is a mutual agreement to engage in sexual activity. It must be clear, coherent, willing, and ongoing.",
        "layout": "standard"
      },
      {
        "title": "Safe Sex",
        "content": "Practicing safe sex reduces the risk of sexually transmitted infections (STIs) and unintended pregnancies.",
        "layout": "standard"
      },
      {
        "title": "Healthy Relationships",
        "content": "Healthy relationships are built on respect, trust, and communication between partners.",
        "layout": "standard"
      },
      {
        "title": "Sexual Orientation",
        "content": "Sexual orientation refers to the pattern of emotional, romantic, or sexual attraction one feels towards others.",
        "layout": "standard"
      }
    ]
  }
}
